export async function seedLiteracyCourses() {
  const { db } = await import("./db");
  const { quests } = await import("@shared/schema");
  if (!db) { console.log("Database not connected. Skipping seeding."); return; }
  console.log("🌱 Seeding EXPANDED financial literacy course library...");

  const { eq } = await import("drizzle-orm");
  
  // Wipe ALL quests for a clean state
  await db.delete(quests);
  console.log("🗑️  Cleared all stale quests.");

  // Insert Challenges
  for (const challenge of CHALLENGE_QUESTS) {
    await db.insert(quests).values(challenge);
    console.log(`✅ Challenge: "${challenge.title}"`);
  }

  // Insert Easy Short Courses (10 min)
  for (const course of EASY_SHORT_COURSES) {
    await db.insert(quests).values(course);
    console.log(`✅ Easy Course (10min): "${course.title}" (${course.points} XP)`);
  }

  // Insert Medium Courses (20-30 min)
  for (const course of MEDIUM_COURSES) {
    await db.insert(quests).values(course);
    console.log(`✅ Medium Course (20-30min): "${course.title}" (${course.points} XP)`);
  }

  // Insert Hard Long Courses (60-90 min)
  for (const course of HARD_LONG_COURSES) {
    await db.insert(quests).values(course);
    console.log(`✅ Hard Course (60-90min): "${course.title}" (${course.points} XP)`);
  }
  
  const total = CHALLENGE_QUESTS.length + EASY_SHORT_COURSES.length + MEDIUM_COURSES.length + HARD_LONG_COURSES.length;
  console.log(`\n✨ Done! ${total} courses and challenges deployed:`);
  console.log(`   📗 ${EASY_SHORT_COURSES.length} Easy courses (10 min)`);
  console.log(`   📘 ${MEDIUM_COURSES.length} Medium courses (20-30 min)`);
  console.log(`   📕 ${HARD_LONG_COURSES.length} Hard courses (60-90 min)`);
  console.log(`   ⚡ ${CHALLENGE_QUESTS.length} Challenge quests`);
}